{$CADDY_DOMAIN} {
	# Public paths (no auth): oauth2 callback, logout, and any favicon
	# request at any subpath. Everything else runs through forward_auth.
	@protected {
		not path /oauth2/* /logout
		not path_regexp ^/.*favicon\.(ico|svg|png)$
	}
	forward_auth @protected localhost:3000 {
		uri /api/auth/verify
		copy_headers Location
	}

	# Global favicon override — every */favicon.{ico,svg,png} request at
	# any subpath is rewritten to /favicon.svg and served by alive-server.
	# Must land BEFORE the per-service imports so it wins matcher priority.
	@favicon path_regexp ^/.*favicon\.(ico|svg|png)$
	handle @favicon {
		rewrite * /favicon.svg
		header Cache-Control "public, max-age=86400"
		reverse_proxy localhost:3000
	}

	import /etc/caddy/conf.d/*.caddy

	handle /* {
		reverse_proxy localhost:3000
	}
}

