132→// validate consumes the state token and returns (returnTo, ok). The entry
133→// is single-use — it is deleted from the store regardless of whether the
134→// caller ends up redirecting to the return URL.
135→func (ss *stateStore) validate(state string) (string, bool) {
136→	ss.mu.Lock()
137→	defer ss.mu.Unlock()
138→
139→	if entry, ok := ss.states[state]; ok {
140→		delete(ss.states, state)
141→		if time.Since(entry.createdAt) < 10*time.Minute {
142→			return entry.returnTo, true
143→		}
144→	}
145→	return "", false
146→}
