148→// --- Public-path registry ---
149→//
150→// Any service that needs a subset of its paths to bypass alive-server's
151→// Google-OAuth gate drops a file into /etc/attlas-public-paths.d/. Each
152→// file is a newline-separated list of path prefixes; '#' starts a comment,
153→// blank lines are ignored. On startup and on SIGHUP the directory is
154→// re-read and an in-memory prefix list is atomically swapped in. The
155→// handleAuthVerify handler consults this list before doing any session
156→// check, returning 200 OK for matches so Caddy forward_auth lets the
157→// request through to the downstream service.
158→//
159→// This exists so services can implement their own auth for specific
160→// endpoints (e.g. petboard's MCP OAuth 2.1 flow, which needs the
161→// /.well-known/*, /token, /register, and /mcp paths to be reachable
162→// without a browser session) without having to modify the base Caddyfile.
163→
164→const defaultPublicPathsDir = "/etc/attlas-public-paths.d"
165→
166→type pathRegistry struct {
167→	mu       sync.RWMutex
168→	prefixes []string
169→}
170→
171→var publicPathRegistry = &pathRegistry{}
172→
173→func publicPathsDir() string {
174→	if dir := os.Getenv("ATTLAS_PUBLIC_PATHS_DIR"); dir != "" {
175→		return dir
176→	}
177→	return defaultPublicPathsDir
178→}
179→
180→// load reads every *.conf file in the configured directory and rebuilds
181→// the in-memory prefix list. Called at startup and on SIGHUP. Safe to
182→// call concurrently with matches().
183→func (r *pathRegistry) load() {
184→	dir := publicPathsDir()
185→	entries, err := os.ReadDir(dir)
186→	if err != nil {
187→		// Not an error — the directory may not exist yet if no service
188→		// has registered paths. Clear the list and move on.
189→		r.mu.Lock()
190→		r.prefixes = nil
191→		r.mu.Unlock()
192→		if !os.IsNotExist(err) {
193→			log.Printf("public-paths: read %s: %v", dir, err)
194→		}
195→		return
196→	}
197→
198→	var prefixes []string
199→	for _, e := range entries {
200→		if e.IsDir() || !strings.HasSuffix(e.Name(), ".conf") {
201→			continue
202→		}
203→		path := filepath.Join(dir, e.Name())
204→		data, err := os.ReadFile(path)
205→		if err != nil {
206→			log.Printf("public-paths: read %s: %v", path, err)
207→			continue
208→		}
209→		for _, line := range strings.Split(string(data), "\n") {
210→			// Strip '#' comments from anywhere on the line, then trim.
211→			if i := strings.Index(line, "#"); i >= 0 {
212→				line = line[:i]
213→			}
214→			line = strings.TrimSpace(line)
215→			if line == "" {
216→				continue
217→			}
218→			// Require prefixes to be absolute paths so an accidental
219→			// empty or relative entry can't match everything.
220→			if !strings.HasPrefix(line, "/") {
221→				log.Printf("public-paths: ignoring non-absolute prefix %q in %s", line, path)
222→				continue
223→			}
224→			prefixes = append(prefixes, line)
225→		}
226→	}
227→
228→	r.mu.Lock()
229→	r.prefixes = prefixes
230→	r.mu.Unlock()
231→	log.Printf("public-paths: loaded %d prefix(es) from %s", len(prefixes), dir)
232→}
233→
234→// matches reports whether the given path starts with any registered
235→// public prefix.
236→func (r *pathRegistry) matches(path string) bool {
237→	if path == "" {
238→		return false
239→	}
240→	r.mu.RLock()
241→	defer r.mu.RUnlock()
242→	for _, p := range r.prefixes {
243→		if strings.HasPrefix(path, p) {
244→			return true
245→		}
246→	}
247→	return false
248→}
