250→// isSafeRelativePath reports whether a candidate return URL can safely be
251→// used as a redirect target. We only accept same-origin relative paths:
252→// must start with '/', must not start with '//' (protocol-relative), and
253→// must parse with an empty scheme and empty host. This prevents open
254→// redirects via a crafted return_to query param.
255→func isSafeRelativePath(p string) bool {
256→	if p == "" || !strings.HasPrefix(p, "/") || strings.HasPrefix(p, "//") {
257→		return false
258→	}
259→	if strings.ContainsAny(p, "\\\r\n") {
260→		return false
261→	}
262→	u, err := url.Parse(p)
263→	if err != nil {
264→		return false
265→	}
266→	return u.Scheme == "" && u.Host == ""
267→}
