func (ss *stateStore) generate(returnTo string) string {
	b := make([]byte, 32)
	rand.Read(b)
	state := hex.EncodeToString(b)

	ss.mu.Lock()
	defer ss.mu.Unlock()

	// Clean expired states
	now := time.Now()
	for k, v := range ss.states {
		if now.Sub(v.createdAt) > 10*time.Minute {
			delete(ss.states, k)
