package main

import (
	"flag"
	"fmt"
	"log"
	"os"
)

func main() {
	log.SetFlags(log.LstdFlags | log.Lmicroseconds)

	if len(os.Args) < 2 {
		fmt.Fprintln(os.Stderr, "usage: petboard <serve|migrate>")
		os.Exit(2)
	}
	switch os.Args[1] {
	case "serve":
		runServe(os.Args[2:])
	case "migrate":
		runMigrate(os.Args[2:])
	default:
		fmt.Fprintf(os.Stderr, "petboard: unknown subcommand %q\n", os.Args[1])
		os.Exit(2)
	}
}

func runServe(args []string) {
	fs := flag.NewFlagSet("serve", flag.ExitOnError)
	port := fs.Int("port", envInt("PETBOARD_PORT", 7690), "HTTP listen port")
	dbPath := fs.String("db", envString("PETBOARD_DB", "/var/lib/petboard/petboard.db"), "SQLite path")
	_ = fs.Parse(args)

	log.Printf("petboard scaffold — would bind 127.0.0.1:%d, db=%s", *port, *dbPath)
	log.Printf("serve handler not yet implemented; exiting cleanly so the scaffold compiles")
}

func runMigrate(args []string) {
	fs := flag.NewFlagSet("migrate", flag.ExitOnError)
	dbPath := fs.String("db", envString("PETBOARD_DB", "/var/lib/petboard/petboard.db"), "SQLite path")
	_ = fs.Parse(args)
	log.Printf("petboard scaffold — migrate would run against %s", *dbPath)
}

func envString(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

func envInt(key string, fallback int) int {
	v := os.Getenv(key)
	if v == "" {
		return fallback
	}
	var n int
	if _, err := fmt.Sscanf(v, "%d", &n); err != nil {
		return fallback
	}
	return n
}

